import React from 'react';
import "./ToDoList.css";
import ToDoFormAdd from './ToDoFormAdd';
import Filters from './Filters';
import Item from './Item';

const ToDoList = () => {
    return (
        <div className='container-todo'>
            <h1>TODO List</h1>

            <ToDoFormAdd/>

            <div className="todo">
                <Filters/>

                <div className="list">
                    <Item title="Learn HTML"/>
                    <Item/>
                    <Item/>
                </div>
            </div>
        </div>
    );
}

export default ToDoList;
